const fs = require("fs");
const path = require("path");

const root = process.cwd();

const LIGHT_LOGO_BASE64 = "";
const DARK_LOGO_BASE64 = "";
const COMPONENT_CODE = "\"use client\";\n\nimport { ImgHTMLAttributes, useEffect, useState } from \"react\";\n\ntype LoadLinkLogoProps = ImgHTMLAttributes<HTMLImageElement> & {\n  containerClassName?: string;\n  showGlow?: boolean;\n};\n\nfunction detectDarkMode() {\n  if (typeof window === \"undefined\") return false;\n\n  const savedTheme = localStorage.getItem(\"loadlink-theme\");\n  if (savedTheme === \"dark\") return true;\n  if (savedTheme === \"light\") return false;\n\n  return Boolean(\n    document.querySelector(\"main.bg-black\") ||\n    document.querySelector(\"header.bg-black\") ||\n    document.querySelector(\".bg-black\") ||\n    document.documentElement.classList.contains(\"dark\") ||\n    document.body.classList.contains(\"dark\")\n  );\n}\n\nexport default function LoadLinkLogo({\n  className = \"\",\n  containerClassName = \"\",\n  showGlow = true,\n  alt = \"LoadLink\",\n  ...props\n}: LoadLinkLogoProps) {\n  const [darkMode, setDarkMode] = useState(false);\n\n  useEffect(() => {\n    const sync = () => setDarkMode(detectDarkMode());\n\n    sync();\n\n    const observer = new MutationObserver(sync);\n    observer.observe(document.documentElement, { attributes: true, childList: true, subtree: true });\n    if (document.body) observer.observe(document.body, { attributes: true, childList: true, subtree: true });\n\n    const timer = window.setInterval(sync, 180);\n\n    window.addEventListener(\"storage\", sync);\n    window.addEventListener(\"click\", sync);\n    window.addEventListener(\"loadlink-theme-change\", sync);\n\n    return () => {\n      observer.disconnect();\n      window.clearInterval(timer);\n      window.removeEventListener(\"storage\", sync);\n      window.removeEventListener(\"click\", sync);\n      window.removeEventListener(\"loadlink-theme-change\", sync);\n    };\n  }, []);\n\n  return (\n    <span className={`loadlink-logo-wrap ${containerClassName}`}>\n      {showGlow ? <span aria-hidden=\"true\" className=\"loadlink-logo-glow\" /> : null}\n\n      <img\n        src={darkMode ? \"/images/loadlink-logo-dark.png?v=clean-final\" : \"/images/loadlink-logo-light.png?v=clean-final\"}\n        alt={alt}\n        className={`loadlink-logo-img ${className}`}\n        style={{ filter: \"none\" }}\n        {...props}\n      />\n    </span>\n  );\n}\n";

function write(filePath, content) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, content);
}

function walk(dir, files = []) {
  if (!fs.existsSync(dir)) return files;

  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    if (entry.name === "node_modules" || entry.name === ".next" || entry.name === ".git") continue;

    const full = path.join(dir, entry.name);

    if (entry.isDirectory()) walk(full, files);
    else if (/\.(tsx|jsx)$/.test(entry.name)) files.push(full);
  }

  return files;
}

function ensureLogoImport(code) {
  const importLine = 'import LoadLinkLogo from "@/components/LoadLinkLogo";';
  if (code.includes(importLine)) return code;

  if (code.startsWith('"use client";')) return code.replace('"use client";', '"use client";\n\n' + importLine);
  if (code.startsWith("'use client';")) return code.replace("'use client';", "'use client';\n\n" + importLine);

  const firstImport = code.match(/^import .+?;\n/m);
  if (firstImport) return code.replace(firstImport[0], firstImport[0] + importLine + "\n");

  return importLine + "\n" + code;
}

function extractClassName(tag) {
  const normal = tag.match(/className=["']([^"']*)["']/);
  if (normal) return normal[1].replace(/\s*loadlink-logo-dark-fix\s*/g, " ").trim();

  const template = tag.match(/className=\{`([^`]*)`\}/);
  if (template) return template[1].replace(/\$\{[^}]*\}/g, "").replace(/\s*loadlink-logo-dark-fix\s*/g, " ").trim();

  return "";
}

function isLoadLinkLogoTag(tag) {
  const lower = tag.toLowerCase();

  return (
    lower.startsWith("<img") &&
    (
      lower.includes("loadlink-logo") ||
      lower.includes("loadlink logo") ||
      lower.includes("alt=\"loadlink\"") ||
      lower.includes("alt='loadlink'")
    )
  );
}

function patchLogoTags(code) {
  let count = 0;

  const next = code.replace(/<img\b[\s\S]*?>/g, (tag) => {
    if (!isLoadLinkLogoTag(tag)) return tag;
    count += 1;
    const className = extractClassName(tag);
    return className ? `<LoadLinkLogo className="${className}" />` : "<LoadLinkLogo />";
  });

  return { next, count };
}

function patchPromptBug(code) {
  let next = code;

  // Stop phone-number prompt from firing while the jobs page renders.
  next = next.replace(
    /function buildGreeting\(job: JobListing\) \{[\s\S]*?return `Hey, I’m interested in \$\{subject\} on LoadLink\. Please call me on \$\{requesterNumber \|\| "my number"\} when you are available\.`;\s*\}/,
    `function buildGreeting(job: JobListing, requesterNumber = "") {
  const subject =
    job.group === "Trucks / Trailers"
      ? "this truck"
      : job.group === "Catering / Event"
        ? "this event/catering service"
        : "this farming or mining transport service";

  return \`Hey, I’m interested in \${subject} on LoadLink. Please call me on \${requesterNumber || "my number"} when you are available.\`;
}`
  );

  next = next.replace(
    /async function copyGreeting\(job: JobListing\) \{[\s\S]*?\n\}/,
    `function getRequesterNumber() {
  const savedNumber = localStorage.getItem("loadlink-user-contact-number") || "";
  const requesterNumber = window.prompt("Enter your number to include in the greeting.", savedNumber) || savedNumber;

  if (requesterNumber) localStorage.setItem("loadlink-user-contact-number", requesterNumber);
  return requesterNumber;
}

async function copyGreeting(job: JobListing) {
  const requesterNumber = getRequesterNumber();
  const message = buildGreeting(job, requesterNumber);

  try {
    await navigator.clipboard.writeText(message);
    alert("Greeting copied. You can paste it to the poster.");
  } catch {
    alert(message);
  }
}

function greetPoster(job: JobListing) {
  const requesterNumber = getRequesterNumber();
  const message = buildGreeting(job, requesterNumber);
  const clean = job.contactNumber.replace(/[^\\d+]/g, "");
  const phone = clean.startsWith("0") ? \`27\${clean.slice(1)}\` : clean.replace("+", "");

  if (!phone || phone.toLowerCase().includes("no")) {
    alert(message);
    return;
  }

  window.open(\`https://wa.me/\${phone}?text=\${encodeURIComponent(message)}\`, "_blank");
}`
  );

  next = next.replace(/function whatsappLink\(job: JobListing\) \{[\s\S]*?\n\}/, "");

  // Replace WhatsApp anchor that calls whatsappLink(job) during render with a button that prompts only on click.
  next = next.replace(
    /<a href=\{whatsappLink\(job\)\} target="_blank" rel="noreferrer" className=\{`border px-4 py-3 text-center text-xs font-black uppercase tracking-wide \$\{darkMode \? "border-white\/15 text-white" : "border-black\/10 text-black"\}`\}>Greet poster<\/a>/,
    `<button onClick={() => greetPoster(job)} className={\`border px-4 py-3 text-center text-xs font-black uppercase tracking-wide \${darkMode ? "border-white/15 text-white" : "border-black/10 text-black"}\`}>Greet poster</button>`
  );

  return next;
}

function patchSupabaseWarning(code) {
  let next = code;

  next = next.replace(
    /setNotice\("Shared jobs database is not connected yet\. Check your Supabase environment keys\."\);/g,
    'setNotice("");'
  );

  next = next.replace(
    /Shared jobs database is not connected yet\. Check your Supabase environment keys\./g,
    ""
  );

  return next;
}

function patchGlobals() {
  const globalsPath = path.join(root, "app", "globals.css");
  if (!fs.existsSync(globalsPath)) write(globalsPath, "");

  let css = fs.readFileSync(globalsPath, "utf8");

  // Remove old logo filter blocks that created dirty/blocky results.
  css = css.replace(/\/\* LoadLink dark mode logo fix:[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LOADLINK DARK LOGO FINAL FIX[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LoadLink dark mode business text safety fix[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LoadLink logo swap uses real light\/dark logo files[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LOADLINK EMBEDDED FINAL LOGO SAFETY[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LOADLINK SMOOTH OWNER FIX[\s\S]*?@media \(prefers-reduced-motion: reduce\)[\s\S]*?\}\s*\}\n?/g, "");

  const finalCss = `
/* LOADLINK CLEAN LOGO + SMOOTH THEME FINAL */
html,
body,
main,
header,
section,
article,
footer,
button,
a,
input,
textarea,
select {
  transition-property: background-color, color, border-color, box-shadow, opacity, transform;
  transition-duration: 360ms;
  transition-timing-function: cubic-bezier(.22, .61, .36, 1);
}

.loadlink-logo-wrap {
  position: relative;
  isolation: isolate;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: clamp(132px, 31vw, 168px);
  max-width: 100%;
  overflow: visible;
  background: transparent !important;
}

.loadlink-logo-img {
  position: relative;
  z-index: 2;
  width: 100% !important;
  height: auto !important;
  object-fit: contain !important;
  filter: none !important;
  display: block;
  background: transparent !important;
}

.loadlink-logo-glow {
  position: absolute;
  z-index: 0;
  left: 50%;
  top: 50%;
  width: 118%;
  height: 106%;
  transform: translate(-50%, -50%);
  border-radius: 999px;
  pointer-events: none;
  opacity: .72;
  filter: blur(22px);
  background:
    radial-gradient(circle at 50% 50%,
      rgba(246, 184, 0, .30) 0%,
      rgba(246, 184, 0, .17) 36%,
      rgba(246, 184, 0, .07) 58%,
      rgba(246, 184, 0, 0) 78%);
}

img.loadlink-logo-img,
main.bg-black img.loadlink-logo-img,
header img.loadlink-logo-img,
.bg-black img.loadlink-logo-img {
  filter: none !important;
}

@media (min-width: 768px) {
  .loadlink-logo-wrap {
    width: clamp(148px, 17vw, 184px);
  }
}

@media (prefers-reduced-motion: reduce) {
  html,
  body,
  main,
  header,
  section,
  article,
  footer,
  button,
  a,
  input,
  textarea,
  select {
    transition-duration: 0ms !important;
  }
}
`;

  css += finalCss;
  fs.writeFileSync(globalsPath, css);
}

const changed = [];

write(path.join(root, "public", "images", "loadlink-logo-light.png"), Buffer.from(LIGHT_LOGO_BASE64, "base64"));
write(path.join(root, "public", "images", "loadlink-logo-dark.png"), Buffer.from(DARK_LOGO_BASE64, "base64"));
write(path.join(root, "public", "images", "loadlink-logo.png"), Buffer.from(LIGHT_LOGO_BASE64, "base64"));
write(path.join(root, "components", "LoadLinkLogo.tsx"), COMPONENT_CODE);
changed.push("public/images/loadlink-logo-light.png", "public/images/loadlink-logo-dark.png", "public/images/loadlink-logo.png", "components/LoadLinkLogo.tsx");

const roots = ["app", "components", "src/app", "src/components"]
  .map((folder) => path.join(root, folder))
  .filter((folder) => fs.existsSync(folder));

let patchedLogoTags = 0;

for (const dir of roots) {
  for (const file of walk(dir)) {
    if (file.endsWith(path.join("components", "LoadLinkLogo.tsx"))) continue;

    let code = fs.readFileSync(file, "utf8");
    const before = code;

    const logoResult = patchLogoTags(code);
    code = logoResult.next;
    patchedLogoTags += logoResult.count;

    if (logoResult.count > 0) code = ensureLogoImport(code);
    if (file.endsWith(path.join("app", "jobs", "page.tsx"))) {
      code = patchPromptBug(code);
      code = patchSupabaseWarning(code);
    }

    if (code !== before) {
      fs.writeFileSync(file, code);
      changed.push(path.relative(root, file));
    }
  }
}

patchGlobals();
changed.push("app/globals.css");

write(path.join(root, "loadlink-cleanup-fix-installed.txt"), `Installed at ${new Date().toISOString()}\nPatched logo tags: ${patchedLogoTags}\n`);
changed.push("loadlink-cleanup-fix-installed.txt");

console.log("LOADLINK CLEANUP FIX INSTALLED");
console.log("Patched logo tags:", patchedLogoTags);
console.log("Fixed:");
console.log("- clean transparent logo from reference");
console.log("- less oversized header logo");
console.log("- softer non-blocky gold glow");
console.log("- smoother theme switching");
console.log("- removed scary Supabase message from jobs page");
console.log("- stopped phone number prompt from opening automatically");
console.log("");
console.log("Changed files:");
changed.forEach((file) => console.log("- " + file));
